import{_ as t,o,c as a,a3 as i}from"./chunks/framework.CjquFG0V.js";const m=JSON.parse('{"title":"61. Parental Leave","description":"","frontmatter":{"title":"61. Parental Leave","eba":"Biomedical Engineers 2025-2028","topics":["leave","parental-leave","wages","superannuation"]},"headers":[],"relativePath":"ebas/biomedical-engineers/leave/61-parental-leave.md","filePath":"ebas/biomedical-engineers/leave/61-parental-leave.md"}'),n={name:"ebas/biomedical-engineers/leave/61-parental-leave.md"};function r(s,e,l,p,h,d){return o(),a("div",null,[...e[0]||(e[0]=[i('<h1 id="_61-parental-leave" tabindex="-1">61. Parental Leave <a class="header-anchor" href="#_61-parental-leave" aria-label="Permalink to &quot;61. Parental Leave&quot;">​</a></h1><p>This clause deals with parental leave, including paid parental leave. The issue of superannuation and parental leave (both paid and unpaid) is addressed at subclause 30.6.</p><p><strong>61.1</strong> Structure of Clause This clause 61 is structured as follows:</p><p><strong>(a)</strong> Structure of Clause: subclause 61.1;</p><p><strong>(b)</strong> Definitions: subclause 61.2;</p><p><strong>(c)</strong> Unpaid Parental Leave: subclause 61.3;</p><p><strong>(d)</strong> Hospitalised Children – Agreement to Not Take Unpaid Parental Leave: subclause 61.4;</p><p><strong>(e)</strong> Flexible Parental Leave – Unpaid: subclause 61.5;</p><p><strong>(f)</strong> Paid Parental Leave: subclause 61.6;</p><p><strong>(g)</strong> Notice and Evidence Requirements: subclause 61.7;</p><p><strong>(h)</strong> Parental Leave Associated with the Birth of a Child – Additional Provisions: subclause 61.8;</p><p><strong>(i)</strong> Where Placement Does Not Proceed or Continue: subclause 61.9;</p><p><strong>(j)</strong> Special Parental Leave: subclause 61.10;</p><p><strong>(k)</strong> Variation of Period of Unpaid Parental Leave (up to 12 months): subclause 61.11;</p><p><strong>(l)</strong> Right to Request Extension of Period of Unpaid Parental Leave Beyond 12 Months: subclause 61.12;</p><p><strong>(m)</strong> Parental Leave and Other Entitlements: subclause 61.13;</p><p><strong>(n)</strong> Transfer to a Safe Job: subclause 61.14;</p><p><strong>(o)</strong> Returning to Work after a Period of Parental Leave: subclause 61.15;</p><p><strong>(p)</strong> Replacement Employees: subclause 61.16;</p><p><strong>(q)</strong> Communication During Parental Leave – Organisational Change: subclause 61.17; and</p><p><strong>(r)</strong> Keeping in Touch Days: subclause 61.18. Other provisions associated with parental leave are also included in this Agreement. Specifically, prenatal leave at <a href="/eba/ebas/biomedical-engineers/leave/59-pre-natal-leave.html">clause 59</a>, flexible working arrangements which includes the right to request to return from parental leave on a part-time basis at <a href="/eba/ebas/biomedical-engineers/workplace-rights/85-flexible-working-arrangements.html">clause 85</a>, leave to attend interviews and examinations relevant to adoption leave (pre-adoption leave) at <a href="/eba/ebas/biomedical-engineers/leave/60-pre-adoption-leave.html">clause 60</a> and breastfeeding at <a href="/eba/ebas/biomedical-engineers/leave/62-breastfeeding.html">clause 62</a>.</p><p><strong>61.2</strong> Definitions For the purposes of this clause 61:</p><p><strong>(a)</strong> Child means:</p><p><strong>(i)</strong> in relation to birth-related leave, a child (or children from a multiple birth) of the Eligible Employee or the Eligible Employee’s Spouse;</p><p><strong>(ii)</strong> in relation to adoption-related leave, a child (or children) under sixteen (16) (as at the day of placement or expected day of placement) who is placed or who is to be placed with the Eligible Employee for the purposes of adoption, other than a child or step-child of the Eligible Employee or of the Spouse of the Eligible Employee or a child who has previously lived continuously with the Eligible Employee for a period of six (6) months or more (Adopted Child); or</p><p><strong>(iii)</strong> as the case requires, includes a Stillborn Child.</p><p><strong>(b)</strong> Continuous Service includes:</p><p><strong>(i)</strong> continuous service with one and the same Employer, or</p><p><strong>(ii)</strong> continuous service with more than one Employer including Institutions or Statutory Bodies (as defined at subclause 63.1(e) and (j)); and</p><p><strong>(iii)</strong> includes any period of employment that would count as service under the Act, and</p><p><strong>(iv)</strong> an Allowable Period of absence (as defined at subclause 63.1(a)).</p><p><strong>(c)</strong> Eligible Casual Employee means a casual Employee that has been employed by the Employer on a regular and systematic basis for a sequence of periods of employment during a period of at least 12 months and who has, but for the birth or expected birth of a Child or the decision to adopt a Child, a reasonable expectation of continuing engagement by the Employer on a regular and systematic basis.</p><p><strong>(d)</strong> Eligible Employee for the purposes of this clause 61 means a non-casual Employee who has at least 6 months’ Continuous Service or an Eligible Casual Employee as defined above.</p><p><strong>(e)</strong> Employee Couple has the same meaning as under the Act.</p><p><strong>(f)</strong> Flexible Parental Leave means the 100 days’ unpaid parental leave an Eligible Employee may take under subclause 61.5 as part of their 52 weeks&#39; entitlement of Parental Leave.</p><p><strong>(g)</strong> Unpaid Parental Leave means the 52 weeks’ parental leave an Eligible Employee may take under subclause 61.3.</p><p><strong>(h)</strong> Notional Flexible Period is the period during which the Eligible Employee would be on Flexible Parental Leave if the Eligible Employee took leave for all of the Eligible Employee&#39;s notified flexible days in a single continuous period.</p><p><strong>(i)</strong> Stillbirth means the delivery of a Stillborn Child.</p><p><strong>61.3</strong> Unpaid Parental Leave</p><p><strong>(a)</strong> An Eligible Employee is entitled to 12 months’ Unpaid Parental Leave if:</p><p><strong>(i)</strong> the leave is associated with: <strong>(A)</strong> the birth, or expected birth, of a Child (including a Stillbirth) of the Eligible Employee or the Eligible Employee’s Spouse; or <strong>(B)</strong> the placement of a Child with the Eligible Employee for adoption; and</p><p><strong>(ii)</strong> the Eligible Employee has or will have a responsibility for the care of the Child, or in the case of a Stillbirth, the Eligible Employee would have had a responsibility for the care of the Child if the Child had been born alive.</p><p><strong>(b)</strong> Except as provided at subclause 61.5 (Flexible Parental Leave - Unpaid) and subclause 61.18 (Keeping in Touch Days), the Eligible Employee must take the leave in a single continuous period.</p><p><strong>(c)</strong> Each member of an Employee Couple may take a separate period of up to 12 months of Unpaid Parental Leave.</p><p><strong>(d)</strong> An Eligible Employee may be able to extend a period of unpaid parental leave in accordance with subclause 61.12 (Right to Request an Extension of Period of Unpaid Parental Leave Beyond 12 Months).</p><p><strong>61.4</strong> Hospitalised Children – Agreement to Not Take Unpaid Parental Leave</p><p><strong>(a)</strong> If:</p><p><strong>(i)</strong> a Child is required to remain in hospital after the Child&#39;s birth, or is hospitalised immediately after the Child&#39;s birth, including because: <strong>(A)</strong> the Child was born prematurely; <strong>(B)</strong> the Child developed a complication or contracted an illness during the child&#39;s period of gestation or at birth; or <strong>(C)</strong> the Child developed a complication or contracted an illness following the Child&#39;s birth; and</p><p><strong>(ii)</strong> an Employee, whether before or after the birth of the Child, gives notice in accordance with subclause 61.7 of the taking of a period of unpaid parental leave (the original leave period) in relation to the Child; then the Employee may agree with their Employer that the Employee will not take unpaid parental leave for a period (the permitted work period) while the Child remains in hospital.</p><p><strong>(b)</strong> If the Employee and Employer so agree, then the following rules have effect:</p><p><strong>(i)</strong> the Employee is taken to not be taking unpaid parental leave during the permitted work period;</p><p><strong>(ii)</strong> the permitted work period does not break the continuity of the original leave period; and</p><p><strong>(iii)</strong> the Employee is taken to have advised the Employer, for the purposes of subclause 61.7(c), of an end date for the original leave period that is the date on which that period would end if it were extended by a period equal to the permitted work period.</p><p><strong>(c)</strong> The permitted work period must start after the birth of the Child.</p><p><strong>(d)</strong> The permitted work period ends at the earliest of the following:</p><p><strong>(i)</strong> the time agreed by the Employer and Employee;</p><p><strong>(ii)</strong> the end of the day of the Child&#39;s first discharge from hospital after birth; or</p><p><strong>(iii)</strong> if the Child dies before being discharged, the end of the day the Child dies.</p><p><strong>(e)</strong> Only one (1) period may be agreed to under subclause 61.4(a) for which the Employee will not take unpaid parental leave in relation to the Child.</p><p><strong>(f)</strong> The Employee must, if required by the Employer, give the Employer evidence (including without limitation, a medical certificate) that would satisfy a reasonable person of either or both of the following:</p><p><strong>(i)</strong> that subclause 61.4(a)(i) applies in relation to the child;</p><p><strong>(ii)</strong> that the Employee is fit for work.</p><p><strong>61.5</strong> Flexible Parental Leave - Unpaid</p><p><strong>(a)</strong> An Eligible Employee may take up to 100 days of their Unpaid Parental Leave entitlement (Flexible Parental Leave) during the 24-month period starting on the date of birth (including a Stillbirth) or day of placement of the Child if the requirements of this subclause 61.5 are satisfied in relation to the leave.</p><p><strong>(b)</strong> The number of days of Flexible Parental Leave that the Eligible Employee takes must not be more than the number of flexible days notified to the Employer under subclause 61.7(b)(iv) (subject to any agreement under subclause 61.7(b)(v)).</p><p><strong>(c)</strong> Taking Leave That Starts Up to Six (6) Weeks Before the Expected Date of Birth of the Child</p><p><strong>(i)</strong> A pregnant Eligible Employee may take Flexible Parental Leave during the period that starts six (6) weeks before the expected date of birth of the Child.</p><p><strong>(ii)</strong> The amount of Flexible Parental Leave to which an Eligible Employee is entitled under subclause 61.5(a) is reduced by the number of days of Flexible Parental Leave taken under subclause 61.5(c)(i).</p><p><strong>(d)</strong> An Eligible Employee must take the Flexible Parental Leave as:</p><p><strong>(i)</strong> a single continuous period of one (1) or more days; or</p><p><strong>(ii)</strong> separate periods of one (1) or more days each.</p><p><strong>(e)</strong> An Eligible Employee may take the Flexible Parental Leave whether or not they have taken Unpaid Parental Leave under this clause 61.</p><p><strong>(f)</strong> An Eligible Employee may take Flexible Parental Leave after taking one (1) or more periods of unpaid Parental Leave under this clause 61 only if the total of those periods (disregarding any extension under subclause 61.11 or 61.12) is no longer than 12 months, less the employee&#39;s Notional Flexible Period, provided that the calculation for the Employee’s Notional Flexible Period is based on the assumption that:</p><p><strong>(i)</strong> the Eligible Employee ordinarily works each day that is not a Saturday or Sunday; and</p><p><strong>(ii)</strong> there are no public holidays during the period.</p><p><strong>61.6</strong> Paid Parental Leave See also subclause 30.6 (Superannuation during parental leave).</p><p><strong>(a)</strong> From the FFPPOOA commencement of the Agreement, an Eligible Employee commencing unpaid parental leave is entitled to paid parental leave on the following basis:</p><p><strong>(i)</strong> a Primary Carer taking Unpaid Parental Leave will be entitled to 14 weeks’ paid parental leave, provided that the Unpaid Parental Leave is taken contemporaneously with the birth or placement of the Child; and</p><p><strong>(ii)</strong> a non-Primary Carer taking Unpaid Parental Leave will be entitled to 2 weeks’ paid parental leave; save that an Eligible Employee is not entitled to both paid Parental Leave under subclause 61.6(a)(i) and paid Parental Leave under subclause 61.6(a)(ii) in respect of the same birth or adoption.</p><p><strong>(b)</strong> Primary Carer in subclause 61.6(a) means the person who has responsibility for the care of the Child. Only one (1) person can be the Child&#39;s Primary Carer on a particular day.</p><p><strong>(c)</strong> Subclause 61.6(a) is subject to subclause 61.4, in which case the Employee taking Unpaid Parental Leave may agree with the Employer that the Employee will not</p><p>take Unpaid Parental Leave during the permitted work period while the Child remains hospitalised.</p><p><strong>(d)</strong> Payment</p><p><strong>(i)</strong> Payment for paid Parental Leave will be based on the Employee’s ordinary time rate of pay provided in <a href="/eba/ebas/allied-health/appendices/2-wage-rates.html">Appendix 2</a> and will be based on the following: <strong>(A)</strong> Full-time Employee – 38 ordinary hours; <strong>(B)</strong> Part-time Employee – the Employee’s contracted hours, save that where the part-time Employee’s ordinary hours fluctuate because the Employee works additional ordinary shifts (but excluding a permanent variation) an average of the Employee’s ordinary hours over: (1) the preceding 12 months; or (2) the Employee’s period of service where the Employee has less than 12 months service; will apply where this is more favourable to the Employee; or <strong>(C)</strong> Casual Employee – average of the Employee’s ordinary hours of work over the preceding 12 months.</p><p><strong>(ii)</strong> Paid parental leave is in addition to any relevant Commonwealth Government paid parental leave scheme (subject to the requirements of any applicable legislation).</p><p><strong>(iii)</strong> The Employer and Eligible Employee may reach agreement on alternative arrangements as to how the paid Parental Leave under this Agreement is paid. For example, such leave may be paid in smaller amounts over a longer period, consecutively or concurrently with any relevant Commonwealth Government parental leave scheme (subject to the requirements of any applicable legislation) and may include a voluntary contribution to superannuation.</p><p><strong>(iv)</strong> Such agreement must be in writing and signed by the parties. The Eligible Employee must nominate a preferred payment arrangement at least four (4) weeks prior to the expected date of birth or date of placement of the Child.</p><p><strong>(v)</strong> In the absence of agreement, such leave will be paid during the ordinary pay periods corresponding with the period of the leave.</p><p><strong>(vi)</strong> A variation to the payment of paid parental leave resulting in the paid leave being spread over more than 10 weeks does not affect the period of continuous service recognised. For example, an Employee taking 20 weeks at half pay will, for the purpose of calculating continuous service, have ten weeks of continuous service recognised. An Employee taking five (5) weeks at double pay will have 10 weeks of continuous service recognised.</p><p><strong>(vii)</strong> The paid parental leave prescribed by this subclause 61.6 will be concurrent with any relevant unpaid entitlement prescribed by the NES/this Agreement.</p><p><strong>61.7</strong> Notice and Evidence Requirements</p><p><strong>(a)</strong> General Requirement to Give Notice of Taking Parental Leave An Eligible Employee must give the Employer written notice of the taking of Unpaid Parental Leave, or Flexible Parental Leave, or both, by the Eligible Employee.</p><p><strong>(b)</strong> Notice Requirements</p><p><strong>(i)</strong> The Eligible Employee must give the notice to the Employer:</p><p><strong>(A)</strong> at least 10 weeks before starting any of the leave covered by the notice; or <strong>(B)</strong> if that is not practicable, and: (1) the first or only period of leave covered by the notice is Unpaid Parental Leave; or (2) any of the leave covered by the notice starts before the Child’s date of birth or expected date of birth; as soon as practicable (which may be a time after any of the leave covered by the notice has started).</p><p><strong>(ii)</strong> However, if the first or only period of leave covered by the notice is Flexible Parental Leave, the notice may be given at any later time if the Employer agrees.</p><p><strong>(iii)</strong> If any of the leave covered by the notice is Unpaid Parental Leave, the notice must specify the intended start and end dates of the Unpaid Parental Leave.</p><p><strong>(iv)</strong> If any of the leave covered by the notice is Flexible Parental Leave, the notice must specify the total number of flexible days that the Eligible Employee intends to take.</p><p><strong>(v)</strong> If the Employer agrees, the Eligible Employee may: <strong>(A)</strong> reduce the number of flexible days, including by reducing the number of flexible days to zero; or <strong>(B)</strong> increase the number of flexible days, but not so as to increase the number of flexible days above 100.</p><p><strong>(c)</strong> Taking Unpaid Parental Leave – Confirming or Changing Intended Start and End Dates If any of the leave covered by the notice is Unpaid Parental Leave, at least four (4) weeks before the intended commencement of parental leave, or if that is not practicable as soon as practicable, the Eligible Employee must confirm in writing the intended start and end dates of the parental leave, or advise the Employer of any changes to the notice provided in subclause 61.7(a), unless it is not practicable to do so.</p><p><strong>(d)</strong> Flexible Parental Leave – Additional Notice Requirements</p><p><strong>(i)</strong> The Employee must give the Employer written notice of a flexible day on which the Employee will take Flexible Parental Leave: <strong>(A)</strong> at least four (4) weeks before that day; or <strong>(B)</strong> if that is not practicable, as soon as practicable (which may be a time after the leave has started).</p><p><strong>(ii)</strong> If the Employer agrees, the Employee may change a day on which the Employee takes Flexible Parental Leave from a day specified in a notice under subsection 61.7(d)(i).</p><p><strong>(e)</strong> Evidence Requirements</p><p><strong>(i)</strong> The Employer may require the Eligible Employee to provide evidence which would satisfy a reasonable person of: <strong>(A)</strong> in the case of birth-related leave: (1) the date of birth, or expected date of birth of the Child (including without limitation, a medical certificate or certificate from a</p><p>registered midwife, stating the date of birth or expected date of birth); and (2) if relevant, that their Child was Stillborn (including without limitation, a certification by a medical practitioner or registered midwife of the child as having been delivered); or <strong>(B)</strong> in the case of adoption-related leave, the commencement of the placement (or expected day of placement) of the Child and that the Child will be under 16 years of age as at the day of placement or expected day of placement.</p><p><strong>(f)</strong> An Employee will not be in breach of this subclause 61.7 if failure to give the stipulated notice is occasioned by the birth of the Child or placement occurring earlier than the expected date or in other unexpected circumstances. In these circumstances the notice and evidence requirements of this subclause 61.7 should be provided as soon as reasonably practicable.</p><p><strong>61.8</strong> Parental Leave Associated with the Birth of a Child – Additional Provisions</p><p><strong>(a)</strong> Subject to the limits on duration of parental leave set out in this Agreement and unless agreed otherwise between the Employer and Eligible Employee, an Eligible Employee who is pregnant may commence Unpaid Parental Leave at any time up to six (6) weeks immediately prior to the expected date of birth.</p><p><strong>(b)</strong> Six Weeks Before the Birth</p><p><strong>(i)</strong> Where a pregnant Eligible Employee continues to work during the six (6) week period immediately prior to the expected date of birth, the Employer may require the Eligible Employee to provide a medical certificate stating that they are fit for work and, if so, whether it is inadvisable for them to continue in their present position because of illness or risks arising out of the Eligible Employee’s pregnancy or hazards connected with the position.</p><p><strong>(ii)</strong> Where a request is made under subclause 61.8(b)(i) and an Eligible Employee: <strong>(A)</strong> does not provide the Employer with the requested certificate within seven (7) days of the request; or <strong>(B)</strong> within seven (7) days after the request gives the Employer a medical certificate stating that the Eligible Employee is not fit for work; the Employer may require the Eligible Employee to commence their parental leave as soon as practicable.</p><p><strong>(iii)</strong> Where a request is made under subclause 61.8(b)(i) and an Eligible Employee provides a medical certificate that states that the Eligible Employee is fit for work but it is inadvisable for the Eligible Employee to continue in their present position during a stated period, subclause 61.14 (Transfer to a safe job) will apply.</p><p><strong>61.9</strong> Where Placement Does Not Proceed or Continue</p><p><strong>(a)</strong> Where the placement of the Child for adoption with an Eligible Employee does not proceed or continue, the Eligible Employee will notify the Employer immediately.</p><p><strong>(b)</strong> Where the Eligible Employee had, at the time, started a period of adoption-related leave in relation to the placement, the Eligible Employee’s entitlement to adoption- related leave is not affected, except where the Employer gives written notice under subclause 61.9(c).</p><p><strong>(c)</strong> The Employer may give the Eligible Employee written notice that, from a stated day no earlier than four (4) weeks after the day the notice is given, any untaken unpaid adoption-related leave is cancelled with effect from that day.</p><p><strong>(d)</strong> Where the Eligible Employee wishes to return to work due to a placement not proceeding or continuing, the Employer must nominate a time not exceeding four (4) weeks from receipt of notification for the Eligible Employee’s return to work.</p><p><strong>61.10</strong> Special Parental Leave</p><p><strong>(a)</strong> Entitlement to Unpaid Special Birth-Related Leave</p><p><strong>(i)</strong> An Eligible Employee is entitled to a period of unpaid special leave if they are not fit for work during that period because: <strong>(A)</strong> they have a pregnancy-related illness affecting them; or <strong>(B)</strong> all of the following apply: (1) they have been pregnant; and (2) the pregnancy ends after a period of gestation of at least 12 weeks otherwise than by the birth of a living Child; and (3) the birth is not a Stillbirth.</p><p><strong>(ii)</strong> An Eligible Employee who has an entitlement to personal leave may, in part or whole, take personal leave instead of unpaid special leave under this subclause 61.10(a).</p><p><strong>(iii)</strong> Where the pregnancy ends more than 28 weeks from the expected date of birth of the Child, the Eligible Employee is entitled to access any paid and/or unpaid personal leave entitlements in accordance with the relevant personal leave provisions.</p><p><strong>(b)</strong> Entitlement to Paid Special Birth-Related Leave</p><p><strong>(i)</strong> An Eligible Employee is entitled to a period of paid special leave if their pregnancy terminates at or after the completion of 20 weeks’ gestation or the Eligible Employee gives birth but the baby subsequently dies.</p><p><strong>(ii)</strong> Paid special leave is paid leave up to the amount of paid leave available under subclause 61.6(a)(i) (plus superannuation) based on the amount of leave taken, in circumstances where the Employee intended to take Unpaid Parental Leave at the time of birth or placement.</p><p><strong>(iii)</strong> Paid special leave is in addition to any unpaid special leave taken under subclause 61.10(a)(i).</p><p><strong>(iv)</strong> Paid leave available under subclause 61.6(a)(ii) will also apply in these circumstances.</p><p><strong>(c)</strong> Evidence</p><p><strong>(i)</strong> If an Eligible Employee takes leave under this subclause 61.10 the Employer may require the Eligible Employee to provide evidence that would satisfy a reasonable person of the matters referred to in subclause 61.10(a)(i) or 61.10(b)(i) or to provide a certificate from a registered medical practitioner.</p><p><strong>(ii)</strong> The Eligible Employee must give notice to the Employer as soon as practicable, advising the Employer of the period or the expected period of the leave under this provision.</p><p><strong>61.11</strong> Variation of Period of Unpaid Parental Leave (up to 12 months)</p><p><strong>(a)</strong> Where an Eligible Employee has:</p><p><strong>(i)</strong> given notice of the taking of a period of Unpaid Parental Leave under subclause 61.3;</p><p><strong>(ii)</strong> the length of this period of Unpaid Parental Leave as notified to the Employer is less than the Eligible Employee’s available entitlement to Unpaid Parental Leave; and</p><p><strong>(iii)</strong> commenced the period of Unpaid Parental Leave; the Eligible Employee may change the period of parental leave on one (1) occasion. Any change is to be notified (including the new end date for the leave) as soon as possible but no less than four (4) weeks prior to the commencement of the changed arrangements. Nothing in this subclause 61.11 detracts from the basic entitlement in subclause 61.3 (Unpaid Parental Leave) or subclause 61.12 (Right to request an extension of period of unpaid parental leave beyond 12 months).</p><p><strong>(b)</strong> The Eligible Employee’s available parental leave period is 12 months, less any periods of the following kinds:</p><p><strong>(i)</strong> a period of Unpaid Parental Leave that the Employee has been required to take under subclause 61.8(b)(i) or 58.14(b)(v);</p><p><strong>(ii)</strong> if the Employee has given notice in accordance with subclause 61.7(b) of the taking of Flexible Parental Leave—a period equal to the Employee’s Notional Flexible Period.</p><p><strong>(c)</strong> If the Employer and Eligible Employee agree, the Eligible Employee may further change the period of parental leave.</p><p><strong>61.12</strong> Right to Request an Extension of Period of Unpaid Parental Leave Beyond 12 Months</p><p><strong>(a)</strong> An Eligible Employee entitled to Unpaid Parental Leave pursuant to the provisions of subclause 61.3 may request the Employer to allow the Eligible Employee to extend the period of Unpaid Parental Leave by a further continuous period of up to 12 months immediately following the end of the available parental leave period.</p><p><strong>(b)</strong> Request to be in Writing The request must be in writing and must be given to the Employer at least four (4) weeks before the end of the available parental leave period.</p><p><strong>(c)</strong> Response to be in Writing</p><p><strong>(i)</strong> The Employer must give the Eligible Employee a written response to the request within 21 days.</p><p><strong>(ii)</strong> The response must: <strong>(A)</strong> state that the Employer grants the request; <strong>(B)</strong> if, following discussion between the Employer and Employee, the Employer and Employee agree to an extension of unpaid parental leave for a period that differs from the period requested – set out the agreed extended period; or <strong>(C)</strong> state that the Employer refuses the request.</p><p><strong>(d)</strong> Refusal Only in Specific Circumstances The Employer may refuse the request only if:</p><p><strong>(i)</strong> the Employer has: <strong>(A)</strong> discussed the request with the Employee; and</p><p><strong>(B)</strong> genuinely tried to reach an agreement with the Employee about an extension of the period of unpaid parental leave;</p><p><strong>(ii)</strong> the Employer and the Employee have not reached such an agreement;</p><p><strong>(iii)</strong> the Employer has had regard to the consequences of the refusal for the Employee; and</p><p><strong>(iv)</strong> the refusal is on Reasonable Business Grounds.</p><p><strong>(e)</strong> Reasons For Refusal to Be Specified Where the Employer refuses the request, the written response must include:</p><p><strong>(i)</strong> details of the reasons for the refusal;</p><p><strong>(ii)</strong> the Employers particular business grounds for refusal and an explanation of how these grounds apply to the Employee’s request;</p><p><strong>(iii)</strong> either: <strong>(A)</strong> set out the extension to the period of unpaid parental leave (other than the period requested) that the Employer would be willing to agree to; or <strong>(B)</strong> state that there is no extension of the period that the Employer would be willing to agree to; and</p><p><strong>(iv)</strong> set out the effect of subclause 61.12(g), including if a dispute is referred to the Commission.</p><p><strong>(f)</strong> No Extension Beyond 24 Months An Eligible Employee is not entitled to extend the period of Unpaid Parental Leave beyond 24 months after the date of birth or day of placement of the Child.</p><p><strong>(g)</strong> Disputes The dispute resolution procedure in the Agreement will apply to any grievance/dispute arising in relation to a request for an extension of unpaid parental leave beyond 12 months.</p><p><strong>61.13</strong> Parental Leave and Other Entitlements An Eligible Employee may use any accrued annual leave or long service leave entitlements concurrently with Parental Leave, save that taking that leave does not have the effect of extending the period of Parental Leave. If the Employee does so, the taking of that other paid leave does not break the continuity of the period of Parental Leave.</p><p><strong>61.14</strong> Transfer To a Safe Job</p><p><strong>(a)</strong> Where an Employee is pregnant and provides evidence that would satisfy a reasonable person that they are fit for work but it is inadvisable for the Employee to continue in their present position for a stated period (the risk period) because of:</p><p><strong>(i)</strong> illness or risks arising out of the pregnancy; or</p><p><strong>(ii)</strong> hazards connected with the position; the Employee must be transferred to an appropriate safe job if one is available for the risk period, with no other change to the Employee’s terms and conditions of employment.</p><p><strong>(b)</strong> Paid No Safe Job Leave</p><p><strong>(i)</strong> If: <strong>(A)</strong> subclause 61.14(a) applies to a pregnant Eligible Employee but there is no appropriate safe job available;</p><p><strong>(B)</strong> the Eligible Employee is entitled to Unpaid Parental Leave; and <strong>(C)</strong> the Eligible Employee has complied with the notice of intended start and end dates of leave and evidence requirements under subclause</p><p><strong>61.7</strong> for taking Unpaid Parental Leave; then the Eligible Employee is entitled to paid no safe job leave for the risk period.</p><p><strong>(ii)</strong> If the Eligible Employee takes paid no safe job leave for the risk period, the Employer must pay the Eligible Employee at the Eligible Employee’s ordinary rate of pay for the Eligible Employee&#39;s ordinary hours of work in the risk period.</p><p><strong>(iii)</strong> This entitlement to paid no safe job leave is in addition to any other leave entitlement the Eligible Employee may have.</p><p><strong>(iv)</strong> If an Eligible Employee, during the six (6) week period before the expected date of birth, is on paid no safe job leave, the Employer may request that the Eligible Employee provide a medical certificate within seven (7) days stating whether the Eligible Employee is fit for work.</p><p><strong>(v)</strong> If the Eligible Employee has either: <strong>(A)</strong> not complied with the request from the Employer; or <strong>(B)</strong> provided a medical certificate stating that they are not fit for work; then the Eligible Employee is not entitled to paid no safe job leave and the Employer may require the Eligible Employee to take parental leave as soon as practicable.</p><p><strong>(c)</strong> Unpaid No Safe Job Leave If:</p><p><strong>(i)</strong> subclause 61.14(a) applies to a pregnant Employee but there is no appropriate safe job available;</p><p><strong>(ii)</strong> the Employee will not be entitled to Unpaid Parental Leave as at the expected date of birth; and</p><p><strong>(iii)</strong> the Employee has given the Employer evidence that would satisfy a reasonable person of the pregnancy if required by the Employer (which may include a requirement to provide a medical certificate); then the Employee is entitled to unpaid no safe job leave for the risk period.</p><p><strong>61.15</strong> Returning To Work After a Period of Parental Leave</p><p><strong>(a)</strong> An Eligible Employee will endeavour to notify the Employer of their intention to return to work after a period of Unpaid Parental Leave at least four (4) weeks prior to the end of the leave, or where that is not practicable, as soon as practicable.</p><p><strong>(b)</strong> An Eligible Employee will be entitled to return:</p><p><strong>(i)</strong> unless subclause 61.15(b)(ii) or subclause 61.15(b)(iii) applies, to the position which they held immediately before proceeding on parental leave;</p><p><strong>(ii)</strong> if the Eligible Employee was promoted or voluntarily transferred to a new position (other than to a safe job pursuant to subclause 61.14), to the new position;</p><p><strong>(iii)</strong> if subclause 61.15(b)(ii) does not apply, and the Eligible Employee began working part-time because of the pregnancy of the Eligible Employee, or their Spouse, to the position held immediately before starting to work part-time.</p><p><strong>(c)</strong> Subclause 61.15(b) is not to result in the Eligible Employee being returned to the safe job to which the Eligible Employee was transferred under subclause 61.14. In such circumstances, the Eligible Employee will be entitled to return to the position held immediately before the transfer.</p><p><strong>(d)</strong> Where the relevant former position (per subclauses 61.15(b) and 61.15(c) above) no longer exists, an Eligible Employee is entitled to return to an available position for which the Eligible Employee is qualified and suited nearest in status and pay to that of their pre-parental leave position.</p><p><strong>(e)</strong> The Employer must not fail to re-engage an Eligible Employee because:</p><p><strong>(i)</strong> the Eligible Employee or Eligible Employee’s Spouse is pregnant; or</p><p><strong>(ii)</strong> the Eligible Employee is or has been immediately absent on parental leave.</p><p><strong>(f)</strong> The rights of the Employer in relation to engagement and re-engagement of casual Employees are not affected, other than in accordance with this clause 61.</p><p><strong>(g)</strong> Stillbirth or Death of Child – Cancelling Leave or Returning To Work</p><p><strong>(i)</strong> In the event of a Stillbirth, or if a Child dies during the 24-month period starting on the child&#39;s date of birth, then an Eligible Employee who is entitled to a period of parental leave in relation to the Child may: <strong>(A)</strong> before the period of leave starts, give their Employer written notice cancelling the leave; or <strong>(B)</strong> if the period of leave has started, give their Employer written notice that the Employee wishes to return to work on a specified day (which must be at least four (4) weeks after the date on which the Employer receives the notice).</p><p><strong>(ii)</strong> Where notice under subclause 61.15(g)(i) is given, the Employee&#39;s entitlement to Parental Leave in relation to the Child ends: <strong>(A)</strong> if the action is taken under subclause 61.15(g)(i)(A), immediately after the cancellation of the leave; or <strong>(B)</strong> if the action is taken under subclause 61.15(g)(i)(B), immediately before the specified day.</p><p><strong>(iii)</strong> This subclause 61.15(g) does not limit subclause 61.11 (dealing with the Employee varying the period of unpaid parental leave with the agreement of the Employer).</p><p><strong>(h)</strong> Employee Who Ceases to Have Responsibility For Care of Child</p><p><strong>(i)</strong> This subclause 61.15(h) applies to an Employee who has taken unpaid Parental Leave in relation to a Child if the Employee ceases to have any responsibility for the care of the Child for a reason other than because: <strong>(A)</strong> of a Stillbirth; or <strong>(B)</strong> the Child dies during the 24-month period starting on the child&#39;s date of birth.</p><p><strong>(ii)</strong> The Employer may give the Employee written notice requiring the Employee to return to work on a specified day.</p><p><strong>(iii)</strong> The specified day: <strong>(A)</strong> must be at least four (4) weeks after the notice is given to the Employee; and</p><p><strong>(B)</strong> if the leave is birth-related leave taken by an Employee who has given birth, must not be earlier than six (6) weeks after the date of birth of the Child.</p><p><strong>(iv)</strong> The Employee&#39;s entitlement to Parental Leave in relation to the Child ends immediately before the specified day.</p><p><strong>61.16</strong> Replacement Employees</p><p><strong>(a)</strong> A replacement Employee is an Employee specifically engaged or temporarily promoted or transferred, as a result of an Eligible Employee proceeding on parental leave.</p><p><strong>(b)</strong> Before the Employer engages a replacement Employee, the Employer must inform that person of the temporary nature of the employment and of the rights of the Eligible Employee who is being replaced to return to their pre-parental leave position.</p><p><strong>61.17</strong> Communication During Parental Leave – Organisational Change</p><p><strong>(a)</strong> Where an Eligible Employee is on parental leave and the Employer proposes a change or makes a decision that will have a significant effect within the meaning of <a href="/eba/ebas/allied-health/consultation-disputes/13-consultation.html">clause 13</a> (Consultation) of this Agreement on the Eligible Employee’s pre-parental leave position and/or on the status, pay or location of the Eligible Employee’s pre- parental leave position, the Employer will comply with the requirements of clause 13 (Consultation) which include but are not limited to providing:</p><p><strong>(i)</strong> information in accordance with subclause 13.4; and</p><p><strong>(ii)</strong> an opportunity for discussions with the Eligible Employee and, where relevant, the Eligible Employee’s representative in accordance with subclause 13.6.</p><p><strong>(b)</strong> The Eligible Employee will endeavour to take reasonable steps to inform the Employer about any significant matter that arises whilst the Eligible Employee is taking parental leave that will affect the Eligible Employee’s decision regarding the duration of parental leave to be taken, whether the Eligible Employee intends to return to work and whether the Eligible Employee intends to request to return to work on a part-time basis.</p><p><strong>(c)</strong> The Eligible Employee will also notify the Employer of changes of address or other contact details which might affect the Employer’s capacity to comply with subclause 61.17.</p><p><strong>(d)</strong> The Eligible Employee’s pre-parental leave position is:</p><p><strong>(i)</strong> unless subclause 61.17(d)(ii) below applies, the position the Eligible Employee held before starting parental leave;</p><p><strong>(ii)</strong> if, before starting parental leave, the Eligible Employee: <strong>(A)</strong> was transferred to a safe job because of their pregnancy; or <strong>(B)</strong> reduced their working hours due to their pregnancy; the position the Eligible Employee held immediately before that transfer or reduction.</p><p><strong>61.18</strong> Keeping In Touch Days</p><p><strong>(a)</strong> This clause 61 does not prevent an Eligible Employee from performing work for the Employer on a keeping in touch day while the Eligible Employee is taking Parental Leave. If the Eligible Employee does so, the performance of that work does not break the continuity of the period of Parental Leave.</p><p><strong>(b)</strong> Any day or part of a day on which the Eligible Employee performs work for the Employer during the period of leave is a keeping in touch day if:</p><p><strong>(i)</strong> the purpose of performing the work is to enable the Eligible Employee to keep in touch with their employment in order to facilitate a return to that employment after the end of the period of leave;</p><p><strong>(ii)</strong> both the Eligible Employee and Employer consent to the Eligible Employee performing work for the Employer on that day;</p><p><strong>(iii)</strong> the day is not within: <strong>(A)</strong> if the Eligible Employee suggested or requested that they perform work for the Employer on that day – 14 days after the date of birth, or day of placement, of the Child to which the period of leave relates; or <strong>(B)</strong> otherwise – 42 days after the date of birth, or day of placement, of the Child; and</p><p><strong>(iv)</strong> the Eligible Employee has not already performed work for the Employer or another entity on ten days during the period of leave that were keeping in touch days, subject to subclause 61.18(e)(ii).</p><p><strong>(c)</strong> The duration of the work the Eligible Employee performs on that day is not relevant for the purposes of subclause 61.18(b).</p><p><strong>(d)</strong> The Employer must not exert undue influence or undue pressure on an Eligible Employee to consent to a keeping in touch day.</p><p><strong>(e)</strong> For the purposes of subclause 61.18(b)(iv) the following will be treated as two (2) separate periods of unpaid parental leave (meaning that an Eligible Employee can work up to ten (10) keeping in touch days during each period of leave):</p><p><strong>(i)</strong> a period of Unpaid Parental Leave taken during the Eligible Employee’s available parental leave period under subclause 61.3 (Unpaid Parental Leave) and 61.11 (Variation of period of unpaid parental leave (up to 12 months)); and</p><p><strong>(ii)</strong> an extension of the period of Unpaid Parental Leave under subclause 61.12 (Right to request an extension of period of unpaid parental leave beyond 12 months).</p><p><strong>(f)</strong> Subclause 61.18(a) does not apply in relation to the Eligible Employee on and after the first day on which the Employee takes flexible unpaid parental leave in relation to the Child.</p><p>Plain language terms: maternity, paternity, baby leave.</p>',224)])])}const u=t(n,[["render",r]]);export{m as __pageData,u as default};
